  1	import * as React from 'react';
  2	import { pluralize } from '@odf/core/components/utils';
  3	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  4	import { useGetClusterDetails } from '@odf/core/redux/utils';
  5	import {
  6	  NooBaaObjectBucketClaimModel,
  7	  NooBaaObjectBucketModel,
  8	} from '@odf/shared';
  9	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
 10	import {
 11	  useCustomPrometheusPoll,
 12	  usePrometheusBasePath,
 13	} from '@odf/shared/hooks/custom-prometheus-poll';
 14	import { RedExclamationCircleIcon } from '@odf/shared/status/icons';
 15	import { K8sResourceKind } from '@odf/shared/types';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import { referenceForModel } from '@odf/shared/utils';
 18	import { getGaugeValue } from '@odf/shared/utils';
 19	import {
 20	  useK8sWatchResource,
 21	  InventoryItem,
 22	  InventoryItemLoading,
 23	  InventoryItemBody,
 24	  PrometheusResponse,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import { ResourceInventoryItem } from '@openshift-console/dynamic-plugin-sdk-internal';
 27	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 28	import { BucketsTitle } from './buckets-card-item';
 29	import { getObcStatusGroups, getObStatusGroups } from './utils';
 30	import './buckets-card.scss';
 31	
 32	enum BucketsCardQueries {
 33	  BUCKETS_COUNT = 'NooBaa_num_buckets',
 34	  BUCKET_OBJECTS_COUNT = 'NooBaa_num_objects',
 35	  UNHEALTHY_BUCKETS = 'NooBaa_num_unhealthy_buckets',
 36	}
 37	
 38	const objectBucketClaimsResource = {
 39	  kind: referenceForModel(NooBaaObjectBucketClaimModel),
 40	  namespaced: false,
 41	  isList: true,
 42	};
 43	
 44	const objectBucketResource = {
 45	  kind: referenceForModel(NooBaaObjectBucketModel),
 46	  namespaced: false,
 47	  isList: true,
 48	};
 49	
 50	type ObjectInventoryItemProps = {
 51	  isLoading: boolean;
 52	  title: string;
 53	  titlePlural?: string;
 54	  count: number;
 55	  children?: React.ReactNode;
 56	  error?: boolean;
 57	  objectCount?: PrometheusResponse;
 58	  objectCountError?: boolean;
 59	};
 60	
 61	const ObjectInventoryItem: React.FC<ObjectInventoryItemProps> = ({
 62	  isLoading,
 63	  title,
 64	  titlePlural,
 65	  count,
 66	  children,
 67	  error = false,
 68	  objectCount,
 69	  objectCountError,
 70	}) => {
 71	  const titleMessage = pluralize(
 72	    count,
 73	    title,
 74	    titlePlural,
 75	    !isLoading && !error
 76	  );
 77	  return (
 78	    <InventoryItem>
 79	      <div className="co-inventory-card__item-title">
 80	        {isLoading && !error && <InventoryItemLoading />}
 81	        <BucketsTitle objects={objectCount} error={objectCountError}>
 82	          {titleMessage}
 83	        </BucketsTitle>
 84	      </div>
 85	      <InventoryItemBody error={error}>{children}</InventoryItemBody>
 86	    </InventoryItem>
 87	  );
 88	};
 89	
 90	const MCGObjectInventoryItem: React.FC = () => {
 91	  const { t } = useCustomTranslation();
 92	
 93	  const [noobaaCount, noobaaCountError] = useCustomPrometheusPoll({
 94	    query: BucketsCardQueries.BUCKETS_COUNT,
 95	    endpoint: 'api/v1/query' as any,
 96	    basePath: usePrometheusBasePath(),
 97	  });
 98	  const [noobaaObjectsCount, noobaaObjectsCountError] = useCustomPrometheusPoll(
 99	    {
100	      query: BucketsCardQueries.BUCKET_OBJECTS_COUNT,
101	      endpoint: 'api/v1/query' as any,
102	      basePath: usePrometheusBasePath(),
103	    }
104	  );
105	  const [unhealthyNoobaaBuckets, unhealthyNoobaaBucketsError] =
106	    useCustomPrometheusPoll({
107	      query: BucketsCardQueries.UNHEALTHY_BUCKETS,
108	      endpoint: 'api/v1/query' as any,
109	      basePath: usePrometheusBasePath(),
110	    });
111	
112	  const unhealthyNoobaaBucketsCount = Number(
113	    getGaugeValue(unhealthyNoobaaBuckets)
114	  );
115	
116	  return (
117	    <ObjectInventoryItem
118	      isLoading={!(noobaaCount && unhealthyNoobaaBuckets)}
119	      error={!!(noobaaCountError || unhealthyNoobaaBucketsError)}
120	      title={t('NooBaa Bucket')}
121	      count={Number(getGaugeValue(noobaaCount))}
122	      objectCount={noobaaObjectsCount}
123	      objectCountError={!!noobaaObjectsCountError}
124	    >
125	      {unhealthyNoobaaBucketsCount > 0 && (
126	        <>
127	          <RedExclamationCircleIcon />
128	          <span className="nb-buckets-card__buckets-failure-status-count">
129	            {unhealthyNoobaaBucketsCount}
130	          </span>
131	        </>
132	      )}
133	    </ObjectInventoryItem>
134	  );
135	};
136	
137	const ObjectDashboardBucketsCard: React.FC<{}> = () => {
138	  const { t } = useCustomTranslation();
139	
140	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
141	  const { systemFlags } = useODFSystemFlagsSelector();
142	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
143	
144	  const [obcData, obcLoaded, obcLoadError] = useK8sWatchResource<
145	    K8sResourceKind[]
146	  >(objectBucketClaimsResource);
147	  const [obData, obLoaded, obLoadError] =
148	    useK8sWatchResource<K8sResourceKind[]>(objectBucketResource);
149	
150	  return (
151	    <Card>
152	      <CardHeader>
153	        <CardTitle>
154	          {t('Buckets')}
155	          <FieldLevelHelp>
156	            {t(
157	              'Buckets card represents the number of S3 buckets managed on Multicloud Object Gateway and the number of ObjectBucketClaims and the ObjectBuckets managed on both Multicloud Object Gateway and RGW (if deployed).'
158	            )}
159	          </FieldLevelHelp>
160	        </CardTitle>
161	      </CardHeader>
162	      <CardBody>
163	        {isMCGSupported && <MCGObjectInventoryItem />}
164	        <ResourceInventoryItem
165	          isLoading={!obLoaded}
166	          error={!!obLoadError}
167	          kind={NooBaaObjectBucketModel as any}
168	          resources={obData}
169	          mapper={getObStatusGroups}
170	        />
171	        <ResourceInventoryItem
172	          dataTest="resource-inventory-item-obc"
173	          isLoading={!obcLoaded}
174	          error={!!obcLoadError}
175	          kind={NooBaaObjectBucketClaimModel as any}
176	          resources={obcData}
177	          mapper={getObcStatusGroups}
178	        />
179	      </CardBody>
180	    </Card>
181	  );
182	};
183	
184	export const BucketsCard = ObjectDashboardBucketsCard;

